INSERT INTO `ads` VALUES (11,'Professional Contractors','Find certified contractors for your construction projects. Quality workmanship guaranteed.','https://images.pexels.com/photos/3862632/pexels-photo-3862632.jpeg?auto=compress&cs=tinysrgb&w=600','/contractors','Hire Now','Top Rated','providers_sidebar',1,1,'2025-11-23 22:54:42','2025-12-23 22:54:42',1,'developer,supplier,service_provider,customer',NULL,NULL,260,1,0,'sponsored',5000.00,0.00,0.0000,0.00,9,9,'approved',NULL,'2025-11-23 14:54:42','2025-12-23 13:44:58','2025-11-23 22:54:42'),(12,'Architecture & Design Services','Get professional architectural designs and planning services for your dream project.','https://images.pexels.com/photos/157811/pexels-photo-157811.jpeg?auto=compress&cs=tinysrgb&w=600','/design-services','Get Quote','Expert Team','providers_sidebar',2,2,'2025-11-23 22:54:42','2026-01-07 22:54:42',1,'developer,service_provider,customer',NULL,NULL,280,2,0,'sponsored',3000.00,0.00,0.0000,0.00,9,9,'approved',NULL,'2025-11-23 14:54:42','2026-01-07 05:52:29','2025-11-23 22:54:42'),(13,'Project Management Solutions','End-to-end project management services to ensure your construction runs smoothly.','https://images.pexels.com/photos/3184360/pexels-photo-3184360.jpeg?auto=compress&cs=tinysrgb&w=600','/project-management','Learn More','Professional','providers_sidebar',3,3,'2025-11-23 22:54:42','2026-01-22 22:54:42',1,'developer,service_provider',NULL,NULL,415,0,0,'sponsored',4000.00,0.00,0.0000,0.00,9,9,'approved',NULL,'2025-11-23 14:54:42','2026-01-22 08:33:23','2025-11-23 22:54:42'),(14,'Premium Building Materials','Get high-quality construction materials at wholesale prices. Fast delivery across Kenya.','https://images.pexels.com/photos/3945683/pexels-photo-3945683.jpeg?auto=compress&cs=tinysrgb&w=600','/building-materials','Shop Now','Limited Offer','suppliers_sidebar',1,1,'2025-11-23 22:54:42','2025-12-23 22:54:42',1,'developer,service_provider,customer',NULL,NULL,447,3,0,'sponsored',6000.00,0.00,0.0000,0.00,9,9,'approved',NULL,'2025-11-23 14:54:42','2025-12-23 08:35:06','2025-11-23 22:54:42'),(15,'Bulk Order Discounts','Save up to 30% on bulk purchases. Perfect for contractors and large projects.','https://images.pexels.com/photos/4488284/pexels-photo-4488284.jpeg?auto=compress&cs=tinysrgb&w=600','/bulk-orders','View Deals','Special Offer','suppliers_sidebar',2,2,'2025-11-23 22:54:42','2026-01-07 22:54:42',1,'developer,service_provider',NULL,NULL,482,0,0,'sponsored',4500.00,0.00,0.0000,0.00,9,9,'approved',NULL,'2025-11-23 14:54:42','2026-01-07 11:11:36','2025-11-23 22:54:42'),(16,'Premium Residential Projects','Discover luxury apartments and gated communities from top developers. Flexible payment plans available.','https://images.pexels.com/photos/1546168/pexels-photo-1546168.jpeg?auto=compress&cs=tinysrgb&w=600','/residential-projects','View Projects','New Launch','developers_sidebar',1,1,'2025-11-23 22:54:42','2025-12-23 22:54:42',1,'customer',NULL,NULL,1025,3,0,'sponsored',8000.00,0.00,0.0000,0.00,9,9,'approved',NULL,'2025-11-23 14:54:42','2025-12-23 08:34:38','2025-11-23 22:54:42'),(17,'Commercial Space Solutions','Office spaces, retail shops, and commercial buildings. Prime locations with great ROI potential.','https://images.pexels.com/photos/325185/pexels-photo-325185.jpeg?auto=compress&cs=tinysrgb&w=600','/commercial-properties','Explore Options','Hot Deal','developers_sidebar',2,2,'2025-11-23 22:54:42','2026-01-07 22:54:42',1,'service_provider,customer',NULL,NULL,1142,2,0,'sponsored',7000.00,0.00,0.0000,0.00,9,9,'approved',NULL,'2025-11-23 14:54:42','2026-01-07 13:04:33','2025-11-23 22:54:42'),(18,'Find Your Dream Property','Browse thousands of properties from trusted developers and agents across Kenya.','https://images.pexels.com/photos/186077/pexels-photo-186077.jpeg?auto=compress&cs=tinysrgb&w=600','/properties','Browse Now','Popular','homepage_hero',1,1,'2025-11-23 22:54:42','2026-02-21 22:54:42',1,'all',NULL,NULL,0,0,0,'sponsored',10000.00,0.00,0.0000,0.00,9,9,'approved',NULL,'2025-11-23 14:54:42','2025-11-23 14:54:42','2025-11-23 22:54:42'),(19,'Construction Equipment Rental','Rent high-quality construction equipment at affordable rates. Daily and weekly packages available.','https://images.pexels.com/photos/209235/pexels-photo-209235.jpeg?auto=compress&cs=tinysrgb&w=600','/equipment-rental','Rent Now','Best Rates','homepage_sidebar',1,1,'2025-11-23 22:54:42','2026-01-22 22:54:42',1,'developer,service_provider',NULL,NULL,0,0,0,'sponsored',3500.00,0.00,0.0000,0.00,9,9,'approved',NULL,'2025-11-23 14:54:42','2025-11-23 14:54:42','2025-11-23 22:54:42'),(20,'Real Estate Investment Opportunities','Exclusive investment opportunities with high returns. Pre-launch projects and prime locations.','https://images.pexels.com/photos/534220/pexels-photo-534220.jpeg?auto=compress&cs=tinysrgb&w=600','/investments','Invest Now','High ROI','search_results',1,1,'2025-11-23 22:54:42','2026-02-06 22:54:42',1,'developer,customer',NULL,NULL,0,0,0,'sponsored',9000.00,0.00,0.0000,0.00,9,9,'approved',NULL,'2025-11-23 14:54:42','2025-11-23 14:54:42','2025-11-23 22:54:42');
