INSERT INTO `beke_users` VALUES (50,'STAROOT REAL ESTATE','staroot-real-estate','hello@starootcompany.com','+254710999111','$2b$10$i7cIAtOkmGcEoM47kmd9Ge/PVqyck5Rm8VhA5RSYFiJBXylBv5nM6','developer','STAROOT REAL ESTATE','storage/company/logos/76fc3e03-d899-43df-90e8-6fb00c4f143f.jpg','https://starootcompany.com/gemini/','Principle place, School lane ,Westlands, Nairobi Kenya','We’ve provided exceptionally high-quality homes in the best of Nairobi inspired by art, owner’s aspiration, and customers’ taste.',NULL,NULL,NULL,'Nairobi','Main office','hello@starootcompany.com','+254710999111',0,'approved',NULL,0,NULL,NULL,'2025-12-10 17:40:58','2025-12-11 14:55:55',NULL,0.00,0,0,18,18,35,2007,NULL,'storage/company/cover-images/10e2cd92-a954-4f60-a778-990c6199dc2a.jpg','Since founding in 2007, Staroot Real Estate has steadily grown into one of Kenya’s most recognized and trusted real estate developers. Our journey over the past 18 years has been defined by innovation, quality, and integrity — building homes and communities that reflect modern design and dependable value.\r\n\r\nWe’ve provided exceptionally high-quality homes in the best of Nairobi inspired by art, owner’s aspiration, and customers’ taste. Our properties are a combination of classic and contemporary design, built to meet different customers’ tastes and ultimately provide an experience where they can enjoy the exuberance of life.','Westlands',NULL,NULL,'[]','[]','[\"Home construction\"]','[\"High-rise apartments\"]',NULL,'admin',13,NULL,NULL,NULL,NULL,0,0,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(51,'WONDER PROPERTIES','wonder-properties','info@wonderpropertieskenya.com','+254702818888','$2b$10$kumFNqHgvqg.JZN7Tz3z7OBasxQ90BSjMPkY0lBHIw3le1zAAZSoC','developer','WONDER PROPERTIES','storage/company/logos/ed677ca5-ff89-40a1-9bbb-358cb2cd5b27.jpg','https://www.wonderpropertykenya.com/#/','Kirichwa Road,off Argwings Kodhek, Kilimani ,Nairobi','Wonder Properties is a leading Real Estate brand dedicated to transforming your dreams into reality. With a passion for excellence and a commitment to our client\'s satisfaction, we specialize in providing convenient and harmonious living environments. Whether you\'re seeking your dream home or a sound investment opportunity, Wonder Properties has you covered.',NULL,NULL,NULL,'Nairobi','Main Office','info@wonderpropertykenya.com','+254702818888',0,'approved',NULL,0,NULL,NULL,'2025-12-10 19:04:59','2025-12-10 19:23:48','Wonderful Life',0.00,0,0,10,10,1,2015,NULL,'storage/company/cover-images/af57720b-38c2-4131-b163-32a4e51c4af4.jpg','Established in 2015, Wonder Properties has quickly risen to prominence in the real estate industry. Our journey began with a simple yet profound mission: to offer top-tier real estate solutions tailored to our clients\' unique desires and requirements. Since our inception, we\'ve relentlessly pursued this goal, earning the trust and loyalty of countless satisfied clients along the way.','Kilimani',NULL,NULL,'[]','[]','[\"Project Management\", \"General Contracting\", \"Renovation and Remodelling\", \"Site preperation\", \"Design building services\", \"Green Building and Sustainability\"]','[\"Project Management\", \"Design building services\"]',NULL,'admin',13,NULL,NULL,NULL,NULL,4,500,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(52,'EVERWOOD PROPERTIES','everwood-properties','info@luminara.com','+254117668888','$2b$10$D7QwDt.G2vMwUL68lwwiTuq9WAYu6aAMO6Dv745WokFCUeDYvi3OK','developer','EVERWOOD PROPERTIES','storage/company/logos/e8819a95-3ca3-4925-9c68-3c8917d5a2ae.jpg','https://www.luminara.co.ke/','23 Mogotio RD, Westlands','Your Morning Coffee In Bali Starts From Here.',NULL,NULL,NULL,'Nairobi','Main Office','info@luminara.com','+254101666888',0,'approved',NULL,0,NULL,NULL,'2025-12-10 19:57:56','2025-12-11 20:21:54','Born To Shine',0.00,0,0,6,0,1,2025,NULL,'storage/company/cover-images/85cf27bb-7b8c-4086-953b-dbfd98894e3e.jpg',NULL,'Westlands',NULL,NULL,'[]','[]','[]','[]',NULL,'admin',13,NULL,NULL,NULL,NULL,2,31