INSERT INTO `careers` VALUES (4,'REAL ESTATE SALES EXECUTIVE','SALES','Westlands, Nairobi','full-time','<h2><strong>We\'re Hiring ! Sales Executives  (5 positions)</strong></h2>','<ol><li>At least 5 years experience in real estate sales</li><li>Diploma or Degree in sales</li><li>Proven experience in real estate sales</li><li>Excellent communication, negotiation and presentation skills</li><li>Self-motivated ,target-oriented  and results-driven</li><li>Ability to work independently and as part of a team</li><li>Proficiency in Microsoft office and CRM</li></ol>','<ol><li>Identify and pursue new business opportunities to achieve sales targets</li><li>Build and maintain strong relationships with new and existing clients</li><li>Conduct market research to understand customer needs and emerging trends</li><li>Present and promote Beke Africa\'s products and services to prospective clients</li><li>Prepare and deliver sales reports , forecasts and performance analysis</li><li>Collaborate with the marketing and operations teams to ensure customer satisfaction</li></ol><p><br></p><p><br></p><p><br></p><h2><strong><em>Interested candidates  should send their updated CV and cover letter to:[ sales@afbeke.com]</em></strong></h2><h2><strong><em>With the subject Sales Executive Application</em></strong></h2><p><br></p><p><br></p>','open','2025-11-11 09:54:14','2025-11-11 09:54:14',NULL);
