INSERT INTO `customer_follows` VALUES (8,85,11,'She has asked me to contact her after a week, to give them time to decide.','2025-11-20 11:00:00',NULL,NULL,NULL,'pending','2025-11-12 12:10:22','2025-11-12 12:10:22'),(9,45,11,'She still hasn\'t picked up calls, i will try again tomorrow. I have already shared details for Luminara on text','2025-11-13 11:01:00',NULL,NULL,NULL,'pending','2025-11-12 12:13:23','2025-11-12 12:13:23'),(10,91,11,'He has requested i reach out to him In January','2026-01-06 11:00:00',NULL,NULL,NULL,'pending','2025-11-12 12:30:06','2025-11-12 12:30:06'),(11,42,11,'I already shared units for Luminara but he didn\'t like the location. he wanted an apartment close to westgate mall. I shared Diplomat residence which is 30 meters from westgate. He liked this development, just waiting for him to confirm availability of when he\'ll be available for viewing. I will call him tomorrow.','2025-11-13 11:00:00',NULL,NULL,NULL,'pending','2025-11-12 12:45:52','2025-11-12 12:45:52'),(12,84,11,'He is Currently in Nakuru, and will be coming back in the course of the week or next week. He asked me to call him on friday to confirm viewing for next week','2025-11-14 11:00:00',NULL,NULL,NULL,'pending','2025-11-12 12:48:43','2025-11-12 12:48:43'),(13,44,11,'Salah has confirmed viewing for tomorrow 10;30 am . We are going to view Diplomat residence and other projects that the developers have done.','2025-11-13 10:00:00',NULL,NULL,'2025-11-13 22:57:00','pending','2025-11-12 14:58:22','2025-11-12 14:58:22'),(14,92,11,'I will follow up again tomorrow ','2025-11-13 11:00:00',NULL,NULL,NULL,'pending','2025-11-12 15:43:14','2025-11-12 15:43:14'),(15,93,11,'The client would like to view Luminara on Friday','2025-11-13 12:30:00',NULL,NULL,'2025-11-14 09:28:00','pending','2025-11-13 06:28:40','2025-11-13 06:28:40'),(16,107,27,'Benter would like to view Riverside One at 3pm today. Arranging for the same.','2025-11-13 15:00:00',NULL,NULL,'2025-11-13 15:00:00','pending','2025-11-13 11:28:04','2025-11-13 11:28:04'),(17,109,11,'Call them on Monday','2025-11-17 10:30:00',NULL,NULL,NULL,'pending','2025-11-13 11:28:48','2025-11-13 11:28:48'),(18,93,11,'Client has confirmed meeting for tomorrow between 12-1 pm','2025-11-14 10:30:00',NULL,NULL,'2025-11-14 13:00:00','pending','2025-11-13 12:18:54','2025-11-13 12:18:54'),(19,37,23,'We viewed the piece of land on Sunday ni the evening at 5pm. Asking price is 6.5M which the client had proposed to spread across 1 year. The seller is ok with the terms but the buyer also has to do so research based on the type of house they are planning to build with Migaa having limited architects to work with. also there are some regulations that the client wants to revise before committing.','2025-11-15 01:03:00',NULL,NULL,'2025-11-16 17:02:00','pending','2025-11-17 09:03:39','2025-11-17 09:03:39'),(20,143,13,'I did a follow up via call today and she requested  that i share with her the photos for Luminara and also the investment returns calculation table','2025-11-17 15:10:00',NULL,NULL,NULL,'pending','2025-11-17 12:08:39','2025-11-17 12:08:39'),(21,149,27,'Sandra will recover after two weeks and will show her the investment options.','2025-11-28 08:00:00',NULL,NULL,'2025-11-29 11:25:00','pending','2025-11-17 13:26:29','2025-11-17 13:26:29'),(22,38,23,'Client is out of town until January 10th, 2026. He asked to follow up once he is back in Nairobi.','2026-01-10 05:35:00',NULL,NULL,'2026-01-19 05:36:00','pending','2025-11-17 13:36:22','2025-11-17 13:36:22'),(23,60,23,'Is currently on a trip but once they are back on 29th November, they want to view Luminara and Oak west','2025-11-29 05:38:00',NULL,NULL,'2025-11-29 05:39:00','pending','2025-11-17 13:39:27','2025-11-17 13:39:27'),(24,81,22,'Made a follow up on 16th November- she said one of the4 associates has been abroad for medical attention but scheduled to be back in the country by the first week of December. We agreed exchange notes again by 12th December','2025-1