CREATE TABLE `customer_transfers` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `customer_id` int(11) NOT NULL,
  `from_agent_id` int(11) DEFAULT NULL,
  `to_agent_id` int(11) NOT NULL,
  `transferred_by` int(11) NOT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `to_agent_id` (`to_agent_id`),
  KEY `transferred_by` (`transferred_by`),
  KEY `idx_customer_transfers_customer` (`customer_id`),
  KEY `idx_customer_transfers_agents` (`from_agent_id`,`to_agent_id`),
  KEY `idx_customer_transfers_date` (`created_at`),
  CONSTRAINT `customer_transfers_ibfk_1` FOREIGN KEY (`customer_id`) REFERENCES `customers` (`id`) ON DELETE CASCADE,
  CONSTRAINT `customer_transfers_ibfk_2` FOREIGN KEY (`from_agent_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `customer_transfers_ibfk_3` FOREIGN KEY (`to_agent_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `customer_transfers_ibfk_4` FOREIGN KEY (`transferred_by`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
