--
-- Table structure for table `customers`
--

DROP TABLE IF EXISTS `customers`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `customers` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `admin_id` int(11) DEFAULT NULL COMMENT 'Agent or admin assigned to this customer',
  `name` varchar(100) NOT NULL COMMENT 'Customer full name',
  `phone` varchar(30) NOT NULL COMMENT 'Phone number (unique)',
  `email` varchar(100) DEFAULT NULL COMMENT 'Email address',
  `whatsapp` varchar(30) DEFAULT NULL COMMENT 'WhatsApp contact',
  `company_name` varchar(150) DEFAULT NULL COMMENT 'Company or organization',
  `source` enum('walk-in','referral','website','social','event','other') DEFAULT 'other' COMMENT 'How they found BEKE',
  `country` varchar(80) DEFAULT 'Kenya' COMMENT 'Customer country',
  `segment` enum('government','business','individual') DEFAULT 'individual' COMMENT 'Occupation segment',
  `interest` enum('villa','apartment','land','rental') DEFAULT 'villa' COMMENT 'Type of property they want',
  `priority` enum('A','B','C','D') DEFAULT 'C' COMMENT 'Customer priority level',
  `remark` text COMMENT 'General notes about the customer',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Created at',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Last updated at',
  PRIMARY KEY (`id`),
  UNIQUE KEY `phone` (`phone`),
  KEY `admin_id` (`admin_id`),
  CONSTRAINT `customers_ibfk_1` FOREIGN KEY (`admin_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1129 DEFAULT CHARSET=utf8mb4;
/*!40101 SET character_set_client = @saved_cs_client */;

