  KEY `idx_developer_leads_developer_id` (`developer_id`),
  KEY `idx_developer_leads_status` (`status`),
  KEY `idx_developer_leads_created_at` (`created_at`),
  KEY `idx_developer_leads_project_id` (`project_id`),
  CONSTRAINT `developer_leads_ibfk_1` FOREIGN KEY (`developer_id`) REFERENCES `beke_users` (`id`),
  CONSTRAINT `developer_leads_ibfk_2` FOREIGN KEY (`project_id`) REFERENCES `developer_projects` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
