DROP TABLE IF EXISTS `developer_projects`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `developer_projects` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `developer_id` int(11) NOT NULL,
  `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `location` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `project_type` enum('residential','commercial','mixed_use','land') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('planning','ongoing','completed','upcoming') COLLATE utf8mb4_unicode_ci DEFAULT 'planning',
  `total_units` int(11) DEFAULT NULL,
  `units_sold` int(11) DEFAULT '0',
  `starting_price` decimal(15,2) DEFAULT NULL,
  `completion_date` date DEFAULT NULL,
  `cover_image` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `developer_id` (`developer_id`),
  CONSTRAINT `developer_projects_ibfk_1` FOREIGN KEY (`developer_id`) REFERENCES `beke_users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=50 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
