INSERT INTO `developer_projects` VALUES (11,62,'AJMAL PROJECT','AJMAL PROJECT IN KILIMANI','KILIMANI','commercial','ongoing',50,43,8099999.00,'2025-12-17','/storage/projects/covers/industrial-supply-warehouse-1765712117344.jpeg','2025-12-14 11:35:17','2025-12-14 11:35:17'),(12,77,'Maiyan serviced plots','Welcome to our serviced apartments.','Nakuru','residential','completed',10,10,140000.00,'2024-09-17','/storage/projects/covers/maiyan-villa4-1765961201928.jpeg','2025-12-17 08:46:41','2025-12-17 08:46:41'),(13,77,'Maiyan Villa','Maiyan Villas','Nanyuki','residential','completed',20,18,140000000.00,'2024-05-14','/storage/projects/covers/maiyan-villa3-1765961514717.jpeg','2025-12-17 08:51:54','2025-12-17 08:51:54'),(14,77,'Swara Ranch','Swara Ranch in Nanyuki.','Nanyuki','commercial','completed',8,8,400000.00,'2023-04-17','/storage/projects/covers/maiyan-villa2-1765961745468.jpg','2025-12-17 08:55:45','2025-12-17 08:55:45'),(15,76,'Shams','Shams Residence.','Parklands','residential','completed',54,20,26000000.00,'2025-12-16','/storage/projects/covers/shams-residence-1765963892461.jpeg','2025-12-17 09:31:32','2025-12-17 09:31:32'),(16,76,'Sultana Residency','Sultana Residency','Parklands','residential','ongoing',200,110,13000000.00,'2026-11-17','/storage/projects/covers/sultana-residency-1765967260486.jpeg','2025-12-17 10:27:40','2025-12-17 10:27:40'),(17,75,'Padmore Residence','Padmore Residence','Kilimani','residential','completed',290,290,4600000.00,'2024-06-17','/storage/projects/covers/padmore-residence-1765968087401.png','2025-12-17 10:41:27','2025-12-17 10:41:27'),(18,75,'Tsavorit  Garden','Tsavorite Garden','Kilimani','residential','ongoing',310,201,5500000.00,'2026-12-17','/storage/projects/covers/tsavorite-gardens-1765968304063.png','2025-12-17 10:45:04','2025-12-17 10:45:04'),(19,75,'Skyline','Skyline','Kilimani','residential','completed',288,198,5500000.00,'2026-12-17','/storage/projects/covers/skyline-1765968479005.jpeg','2025-12-17 10:47:59','2025-12-17 10:47:59'),(20,74,'Isra Residency','Isra Residency','Parklands','residential','planning',271,199,11000000.00,'2025-12-25','/storage/projects/covers/isra-residency-1765968896606.jpg','2025-12-17 10:54:56','2025-12-17 10:54:56'),(21,74,'Lumina Residency','Lumina Residency','Raphta Road','residential','planning',215,100,6600000.00,'2026-03-17','/storage/projects/covers/lumina-residency-1765969324079.jpg','2025-12-17 11:02:04','2025-12-17 11:02:04'),(22,74,'Khadra Plaza','Khadra Plaza','Eastleigh','residential','planning',314,290,15000000.00,'2025-06-17','/storage/projects/covers/khadra-plaza-1765969550462.jpg','2025-12-17 11:05:50','2025-12-17 11:05:50'),(23,72,'Kings Eden Garden','Kings Eden Garden','Lavington','residential','completed',322,300,13500000.00,'2022-05-17','/storage/projects/covers/kings-eden-garden-1765970812285.jpg','2025-12-17 11:26:52','2025-12-17 11:26:52'),(24,79,'The Marquis','The Marquis','Kileleshwa','residential','completed',311,299,23202000.00,'2024-04-17','/storage/projects/covers/marquis-1765973042007.jpg','2025-12-17 12:04:02','2025-12-17 12:04:02'),(25,79,'The Address Office Spaces','THE ADDRESS’ has been designed to make each day more inspired and productive. ‘THE ADDRESS’ is the perfect environment for building a successful business, because we believe that tomorrow’s success must be designed today.','Westlands','commercial','completed',200,195,5000000.00,'2019-10-17','/storage/projects/covers/the-address-1765974614057.jpg','2025-12-17 12:30:14','2025-12-17 12:30:14'),(26,79,'The Crescent','The Crescent is designed to serve Kenya’s growing middle-income group by providing value housing within the city, offering comfortable living spaces, modern finishes and amenities in Kileleshwa”\r\n\r\nThe Crescent symbol has been used since ancient times to represent silver. Like silver, The Crescent Apartments is a precious and shining development in the heart of Kileleshwa, on Gatundu Crescent overlooking the beautiful Kenya High School.','Kileleshwa','residential','completed',188,111,6600000.00,'2017-11-17','/storage/projects/covers/the-crescent-1765976557542.jpg','2025-12-17 13:02:37','2025-12-17 13:02:37'),(27,71,'Impala Heights','Located in the serene and fast-growing area of Thindigua, just 600 meters off Kiambu Road, Impala Heights Apartments offer an exceptional living experience.\r\n\r\nSitting on 1 acre of land, these new 2 and 3-bedroom apartments for sale are strategically situated providing both investors and residents with outstanding value, offering high rental yields and a full residential experience.\r\n\r\nImpala Heights is Thindigua’s urban jungle having set aside over 1,000 SQM of green space redefining modern residential living. These investment-turn key apartments will provide investors with a unique and excellent return on their investment changing the landscape of Thindigua’s Real Estate Market.\r\n\r\nThindigua’s location on Kiambu Road ensures that Impala Heights is not just a home, but a well-connected hub for both work and leisure.','Thindigua','residential','ongoing',294,155,9000000.00,'2027-03-17','/storage/projects/covers/impla-heights-1765978266320.jpg','2025-12-17 13:31:06','2025-12-17 13:31:06'),(28,81,'Wen Hui Pavilion','The project is located in Baoshui New District, next to Chongren No.1Middle School, alongside hospitals, schools, shopping malls, parks and other living facilities.','Chaina','commercial','completed',100,100,2000000000.00,'2025-12-22','/storage/projects/covers/nan-project-1766045661131.jpg','2025-12-18 08:14:21','2025-12-18 08:14:21'),(29,81,'Yu Gan Kai Yuan ','The hotel is located in the center of Yugan County, Shangrao City,Jiangxi Province, covering a total area of 132 mu, of which the hotel covers an area of 32 mu, with a total construction area of about 30,000 square meters and an investment of about 280 million yuan.The hotel has about 240 deluxe rooms of all kinds, supporting the full-day restaurant, a la carte restaurant, banquet restaurant, about 1000m multi-function hall, small and medium-sized meeting rooms, gym and other leisure and entertainment facilities. The hotel has been opened in 2022, is the largest and highest grade five-star hotel in Yugan County.','Chaina','commercial','completed',240,240,100000000000.00,'2022-05-18','/storage/projects/covers/yu-gan-kai-yuan-hotel-1766046263333.jpg','2025-12-18 08:24:23','2025-12-18 08:24:23'),(30,81,'Liuyang Intercontinental Hotel','The project is located in the world-famous \'Hometown of Fireworks\' Liuyang City, with a planned operating area of about 38,000 square meters and a total investment of about 400 million yuan. The hotel is set within a 198-meter landmark super high-rise complex and is scheduled to be put into use in November 2023.','Chaina','commercial','completed',240,240,20000000.00,'2023-10-18','/storage/projects/covers/liu-yang-intercontinental-hotel-1766047820455.jpg','2025-12-18 08:50:20','2025-12-18 08:50:20'),(31,82,'Fountain Residence','Fountain Residency, located at the junction of Kirichwa Road & Muringa Road in Kilimani, is your chance to own a modern home in one of Nairobi’s most sought-after neighborhoods. Just minutes from Yaya Centre, Junction Mall, schools, hospitals, and major transport links, it offers unmatched convenience and strong investment appeal.','Kilimani','residential','upcoming',312,20,5000000.00,'2028-12-18','/storage/projects/covers/fountain-residence-1766054304396.jpg','2025-12-18 10:38:24','2025-12-18 10:38:24'),(32,82,'Aya Luxury Residence','Nairobi, the heartbeat of Kenya’s real estate scene is constantly evolving, embracing modernity with its superb skyline of urban developments. In the midst of this growth wave, a new beacon of innovation unveils at the junction of Othaya Road and Makueni Road, a magnificent project poised to transcend luxury and redefine the urban lifestyle.\r\n\r\nWelcome to Aya Luxury Residence, our newest project in Kileleshwa, Nairobi.\r\nBoasting its strategic location, Aya sets itself apart with a unique combination of private garden villas, Sky villas with a rooftop garden, spacious duplex apartments and the typical 2,3,4,5-bed apartments complemented by stunning amenities.\r\n','Kileleshwa','residential','upcoming',300,88,10000000.00,'2028-12-18','/storage/projects/covers/aya-luxury-residence-1766055970561.jpg','2025-12-18 11:06:10','2025-12-18 11:06:10'),(33,82,'Haven Villas','Haven Villas is a wondrous modern villa project situated in the most coveted address along Loiyangalani Road, Lavington, Nairobi.\r\n\r\nThis exclusive sanctuary is meant to restore the art of refined living in the heart of Lavington with 8 meticulously designed 6-bedroom triplex villas plus a DSQ.\r\n\r\nThis project will bring out unparalleled elegance and absolute tranquility with keen details to every finishing.','Lavington, Loiyangalani','residential','upcoming',8,3,90000000.00,'2027-07-18','/storage/projects/covers/haven-villa-1766056758539.jpg','2025-12-18 11:19:18','2025-12-18 11:19:18'),(34,84,'G.T.C Residence','Step into the vibrant and diverse new neighborhood of Nairobi, where an unmatched way of living awaits. Stay and invest in GTC residence apartments, nestled amidst stylish restaurants, cafes, and a shopping mall.\r\n\r\nWelcome to GTC residence, the epitome of a residential, offering a lifestyle that is truly unparalleled.','Westlands','residential','completed',514,300,28860000.00,'2022-06-18','/storage/projects/covers/gtc-about-3-1766063826601.jpg','2025-12-18 13:17:06','2025-12-18 13:17:06'),(35,83,'Canto Residence','Tucked in the leafy suburbs of Westlands along School Lane are these prestigious and luxurious developments featuring studio & 1 Bedroom apartment units available for Sale. The development is designed with the highest quality materials, creating an inviting living atmosphere that fulfills all wishes.\r\n\r\n\r\n\r\n','Westlands','residential','upcoming',275,66,6446700.00,'2028-11-19','/storage/projects/covers/canto-1766140436713.jpg','2025-12-19 10:33:56','2025-12-19 10:33:56'),(36,83,'Divine Residence','Divine residence is truly a treasure waiting to be discovered. Not only is each apartment designed with international hotel standards in mind, but it is furnished with custom-made furniture created specifically for it. Every detail in design, finishing, and furnishing is directly hand-picked by our interior designers to ensure maximum elegance and comfort for future tenants.\r\n\r\n','Riverside dive','residential','ongoing',252,99,18850000.00,'2025-12-22','/storage/projects/covers/divine-residence-1766140966111.jpg','2025-12-19 10:42:46','2025-12-19 10:42:46'),(37,83,'Wilma Tower','Designed with the Highest quality, Wilma Towers comprises of studios, 1, 2, and 3-bed apartments. The Wilma Towers creates an inviting living atmosphere that fulfills all wishes. The external Architecture and the interior designs are perfectly combined to create an oasis of calmness in a busy world.','Kilimani','residential','completed',60,60,6648460.00,'2025-02-03','/storage/projects/covers/wilma-towers-1766141560266.png','2025-12-19 10:52:40','2025-12-19 10:52:40'),(38,85,'Eternity Heights','Discover refined living at Eternity Heights, a boutique collection of just 20 upscale units nestled in tranquil Kitisuru west . Each residence -ranging from 2- bedroom duplexes to spacious penthouse thoughtfully designed to offer comfort , elegance and value.\r\n\r\n\r\n\r\nFeatures:\r\n\r\nModern open kitchen\r\nHigh ceiling windows\r\nLarge balconies\r\nFine finishes\r\nDesignated laundry area\r\nCabro paved parking\r\n\r\n\r\nAmenities:\r\n\r\n\r\n\r\n24 – hour manned gate\r\nCCTV cameras\r\nGym\r\nAmple parking\r\nRooftop entertainment\r\nHigh Speed lift\r\nRooftop Sky Lounge\r\nWell-manicured gardens\r\nCo-Working Space\r\nBeautiful Entrance Lobby\r\n\r\n\r\nUnit sizes and prices:\r\n\r\n\r\n\r\n2Bedroom Duplex 112.56 sqm Ksh 12,500,000\r\n2 Bedroom Duplex 127.44 sqm Ksh 15,850,000\r\n3 Bedroom Penthouse 187.87 sqm Ksh 23,500,000\r\n\r\n\r\nPayment plan:\r\n\r\n\r\n\r\nFlexible Friendly payment Terms\r\n\r\n20% deposit\r\n\r\n60% equal quarterly instalments\r\n\r\n20 % on completion\r\n\r\n\r\n\r\nCompletion date:\r\n\r\nMarch 2026\r\n\r\n\r\n\r\n \r\n\r\n','Kitisuru','residential','ongoing',20,9,12500000.00,'2026-02-05','/storage/projects/covers/eternity-heights-gallery-1767602112833.jpeg','2026-01-05 08:35:12','2026-01-05 08:35:12'),(39,68,'Sage Townhouses','Living in Kitisuru houses unparalleled benefits: serenity from the leafy suburb and proximity to key hubs of Nairobi. With top international schools, world-class health facilities, and premier shopping and fine dining spots just minutes away, the houses at Sage Townhouses combine unmatched convenience with ease of access. The serene environment, encompassed by lush greenery, guarantees a peaceful retreat from the hustle and bustle of the city and is the perfect place to call home.','Kitisuru','residential','completed',12,12,85000000.00,'2022-10-05','/storage/projects/covers/sage-town-house-1767612855536.jpg','2026-01-05 11:34:15','2026-01-05 11:34:15'),(40,68,'Jasper ','Located along the prestigious Muthithi Road, Jasper seamlessly blends residential luxury with commercial convenience.\r\n\r\nJasper offers unparalleled access to Nairobi’s finest amenities. With its strategic location on Muthithi Road, residents are moments away from premier shopping destinations, such as Sarit Centre and Westgate Mall, top-tier medical facilities, international schools, and Nairobi’s business district. Muthithi Road’s connectivity to major roads ensures seamless commutes, making Jasper ideal for professionals and families alike.','Muthithi Road','residential','ongoing',135,99,7800000.00,'2027-07-05','/storage/projects/covers/jasper-1767613313057.jpg','2026-01-05 11:41:53','2026-01-05 11:41:53'),(41,68,'Sunstone Residence','A true depiction of elegance and luxury, this development consists of two, three and four-bedroom apartments at the heart of Westlands. It is located in Westlands overlooking the lush Spring Valley and Karura Forest neighbourhoods.\r\n\r\nThese stylish homes are situated in General Mathenge, Westlands Nairobi, and consist of 2,3 and 4-bedroom apartments for sale.\r\n\r\nPRICES;\r\n\r\n2 BEDROOM UNITS(1700 sqft)- From KSH 22 M\r\n3 BEDROOM UNITS(2400 sqft)– From KSH 36M\r\n4 BEDROOM UNITS(3400 sqft)- From KSH 54.8M\r\n4 BEDROOM UNITS(4800sft) – From KSH 75. M','General Mathenge','residential','completed',54,54,22000000.00,'2025-05-05','/storage/projects/covers/sunstone-gallery-1767613566273.jpg','2026-01-05 11:46:06','2026-01-05 11:46:06'),(42,60,'Emaar Residence','Emaar Residence is a contemporary residential development, positioned perfectly along General Mathenge Road. Just a stone’s throw away from The Sarit Center as well as the Oshwal Academy and College, the Westgate Mall, Mp Shah and Aga khan Hospitals. Emaar Residence is set to be an exclusive living experience to purchase as a home as well as an investment, and will offer a payment plan of up to 4 years with no interest.','General Mathenge','residential','completed',70,65,24000000.00,'2025-12-07','/storage/projects/covers/emaar-residence-1767768211717.jpg','2026-01-07 06:43:31','2026-01-07 06:43:31'),(43,60,'The Stallion Villas','The Stallion Villas, an extraordinary haven of luxury and tranquility located along Kuwinda Road in the prestigious Karen neighborhood. Designed for discerning homeowners, this elegant development redefines upscale living, combining modern sophistication with timeless grace.','Karen ','residential','ongoing',8,3,150000000.00,'2026-11-07','/storage/projects/covers/stallion-villas-1767768644744.jpg','2026-01-07 06:50:44','2026-01-07 06:50:44'),(44,59,'Synina Residence','Synina Residency comprises 3, 4, 5 and 6 Bedroom plus DSQs all en-suite luxury apartments strategically located on Tinderet Avenue, Kileleshwa. Encircled in a haven of scenic views, Synina Residence is conveniently situated in the highly sought after, private and secure neighborhood of Kileleshwa, Nairobi. This development comprises 77 opulent residences thoughtfully constructed with separate domestic living quarters.','Kileleshwa','residential','completed',77,75,30000000.00,'2023-12-05','/storage/projects/covers/synina-residence-33-1767780119454.jpg','2026-01-07 10:01:59','2026-01-07 10:01:59'),(45,59,'Beacon By Synina','Rising gracefully on Mandera Road, Beacon by Synina is an architectural masterpiece redefining luxury living in Nairobi’s upscale Kileleshwa neighborhood. This striking high-rise offers a collection of expansive 3- and 4-bedroom residences with DSQs, alongside lavish 5-bedroom simplex and duplex penthouses, designed for the modern homeowner who values timeless elegance and superior craftsmanship.\r\n\r\nSet in a serene yet well-connected location, Beacon by Synina ensures residents enjoy unmatched convenience. From top schools like Kenton College and The Kenya High School, to vibrant retail hubs such as Yaya Centre, Junction Mall, and ABC Place, everything you need is within minutes. Easy access to the Nairobi Arboretum, Nairobi Hospital, Westlands, Nairobi CBD, and the Expressway makes this residence as practical as it is prestigious.','Kileleshwa','residential','upcoming',67,35,29000000.00,'2026-11-07','/storage/projects/covers/01-street-view-1-1536x1014-1767783843582.jpg','2026-01-07 11:04:03','2026-01-07 11:04:03'),(46,50,'Gemini  Residency','Gemini Residency is an upscale, off-plan residential development located at Matundu  Lane in the prestigious Brookside area of Westlands, Nairobi. This landmark project offers 1 and 2 bedroom apartments designed for contemporary city living, blending refined architecture with spacious layouts and premium finishes perfect for discerning homeowners and savvy  investors alike.','Brookside, Westlands','residential','ongoing',368,111,8700000.00,'2027-11-23','/storage/projects/covers/front-1-1024x687-1767856015999.jpg','2026-01-08 07:06:56','2026-01-08 07:06:56'),(47,51,'Gaia Brookside','Gaia Brookside Forest Apartment is a premier luxury apartment located on Brookside Gardens Drive in Westlands, Nairobi. This exclusive development showcases modern design, exceptional comfort, and unmatched convenience, making it the ideal choice for individuals and families looking to enhance their lifestyles. Offering state-of-the-art amenities and premium living spaces, Gaia Brookside Forest is set to redefine luxury living. The project is in the excavation phase, with construction projected to commence soon.\r\n\r\nCompletion is scheduled for December 2027.','Brookside drive, Westlands','residential','ongoing',228,0,23000000.00,'2027-12-12','/storage/projects/covers/side-1767863670707.jpg','2026-01-08 09:14:30','2026-01-08 09:14:30'),(48,51,'The Diplomat','Discover Diplomat Residencies, an exclusive collection of elegantly designed 1 and 2-bedroom apartments for sale along Peponi Road in Westlands. Set in the heart of Westlands’ vibrant core, The Diplomat blends the sophistication of a high-end hotel with the comfort of home, managed by a renowned hospitality group to deliver a new standard in executive living. Brought to life by Wonder Properties—developers of iconic projects like Alina Harbour, Alina Ridge, and Gaia Brookside—this development speaks to both executives and investors, offering a calculated step toward an elevated future.','Peponi Road ,Westlands','residential','planning',312,222,6100000.00,'2028-05-30','/storage/projects/covers/diplomatexterior-1767864516644.webp','2026-01-08 09:28:36','2026-01-08 09:28:36'),(49,51,'Alina Harbour','Alina Harbour is our current project located along Kirichwa Road ,Off Argwings Kodhek Road,Kilimani Nairobi\r\n\r\nThis project holds luxurious and its design comprises stunning 2 bedrooms ,3 bedrooms and 3 bedrooms with DSQ .The building contains 18 floors 2 basements parking areas lastly a ground floor that will have  shared facilities and parking area. ','Kirichwa road, off Argwings Kodhek Road, Kilimani','residential','completed',460,311,8600000.00,'2025-08-05','/storage/projects/covers/exterior-1-1767868307381.jpg','2026-01-08 10:31:47','2026-01-08 10:31:47');
