--
-- Table structure for table `developer_units`
--

DROP TABLE IF EXISTS `developer_units`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `developer_units` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `developer_id` int(11) NOT NULL,
  `unit_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `project_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `bedrooms` int(11) DEFAULT '0',
  `bathrooms` int(11) DEFAULT '1',
  `area` decimal(10,2) NOT NULL,
  `area_unit` enum('sqft','sqm') COLLATE utf8mb4_unicode_ci DEFAULT 'sqft',
  `price` decimal(15,2) NOT NULL,
  `currency` varchar(3) COLLATE utf8mb4_unicode_ci DEFAULT 'USD',
  `status` enum('available','sold_out','reserved','coming_soon','limited') COLLATE utf8mb4_unicode_ci DEFAULT 'available',
  `unit_type` enum('apartment','villa','townhouse','penthouse','studio','duplex') COLLATE utf8mb4_unicode_ci DEFAULT 'apartment',
  `featured_image` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `floor_plan_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `brochure_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `estimated_completion` date DEFAULT NULL,
  `address` text COLLATE utf8mb4_unicode_ci,
  `latitude` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `longitude` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `amenities` json DEFAULT NULL,
  `specifications` json DEFAULT NULL,
  `display_order` int(11) DEFAULT '0',
  `is_featured` tinyint(1) DEFAULT '0',
  `is_active` tinyint(1) DEFAULT '1',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_developer_id` (`developer_id`),
  KEY `idx_status` (`status`),
