  `alternative_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `property_type_id` int(11) NOT NULL,
  `property_category_id` int(11) NOT NULL,
  `apartment_layout_id` int(11) DEFAULT NULL,
  `country_id` int(11) DEFAULT NULL,
  `county_id` int(11) DEFAULT NULL,
  `constituency_id` int(11) DEFAULT NULL,
  `ward_id` int(11) DEFAULT NULL,
  `detailed_address` text COLLATE utf8mb4_unicode_ci,
  `latitude` decimal(10,8) DEFAULT NULL,
  `longitude` decimal(11,8) DEFAULT NULL,
  `cover_image` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `opening_time` datetime DEFAULT NULL,
  `price_per_sqm` decimal(15,2) DEFAULT NULL,
  `lowest_total_price` decimal(15,2) DEFAULT NULL,
  `highest_total_price` decimal(15,2) DEFAULT NULL,
  `min_area` decimal(10,2) DEFAULT NULL,
  `max_area` decimal(10,2) DEFAULT NULL,
  `property_number` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` longtext COLLATE utf8mb4_unicode_ci,
  `status` enum('show','hide','declined') COLLATE utf8mb4_unicode_ci DEFAULT 'show',
  `decline_reason` text COLLATE utf8mb4_unicode_ci,
  `is_featured` tinyint(1) DEFAULT '0',
  `on_show` enum('yes','no') COLLATE utf8mb4_unicode_ci DEFAULT 'no',
  `sales_status` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `listing_type` enum('sale','rental','land') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'sale',
  `is_recommended` tinyint(1) DEFAULT '0',
  `is_popular` tinyint(1) DEFAULT '0',
  `agent_id` int(11) DEFAULT NULL,
  `sort_order` int(11) DEFAULT '0',
  `views_count` int(11) DEFAULT '0',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `short_description` longtext COLLATE utf8mb4_unicode_ci,
  `seo_title` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `seo_description` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tags` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  `price` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `property_condition_id` int(11) DEFAULT NULL,
  `property_decoration_id` int(11) DEFAULT NULL,
  `property_orientation_id` int(11) DEFAULT NULL,
  `metadata` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  PRIMARY KEY (`id`),
  UNIQUE KEY `slug` (`slug`),
  KEY `apartment_layout_id` (`apartment_layout_id`),
  KEY `country_id` (`country_id`),
  KEY `constituency_id` (`constituency_id`),
  KEY `ward_id` (`ward_id`),
  KEY `idx_property_type` (`property_type_id`),
  KEY `idx_property_category` (`property_category_id`),
  KEY `idx_status` (`status`),
  KEY `idx_sales_status` (`sales_status`),
  KEY `idx_is_featured` (`is_featured`),
  KEY `idx_is_popular` (`is_popular`),
  KEY `idx_agent` (`agent_id`),
  KEY `idx_location` (`county_id`,`constituency_id`,`ward_id`),
  KEY `idx_price_range` (`lowest_total_price`,`highest_total_price`),
  KEY `idx_created_at` (`created_at`),
  FULLTEXT KEY `idx_search` (`property_name`,`alternative_name`,`description`)
) ENGINE=InnoDB AUTO_INCREMENT=407 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
