DROP TABLE IF EXISTS `property_analytics`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `property_analytics` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `property_id` bigint(20) NOT NULL,
  `date` date NOT NULL,
  `views` int(11) DEFAULT '0',
  `enquiries` int(11) DEFAULT '0',
  `bookings` int(11) DEFAULT '0',
  `shares` int(11) DEFAULT '0',
  `conversion_rate` decimal(5,2) GENERATED ALWAYS AS ((case when (`views` > 0) then ((`bookings` / `views`) * 100) else 0 end)) STORED,
  `source` enum('web','mobile','social','referral','email','other') COLLATE utf8mb4_unicode_ci DEFAULT 'web',
  `last_updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_property_date` (`property_id`,`date`),
  KEY `idx_property_id` (`property_id`),
  KEY `idx_date` (`date`),
  KEY `idx_source` (`source`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
