INSERT INTO `testimonials` VALUES (8,'86a25137ea1c9d72','Scholastica  Wakabu','scholastica@gmail.com','Professor','Daystar University','/storage/profile/testimonials/testimonial2-1762582882995.jpg',5,'I\'ll definitely be returning for future projects and highly recommend BEKE Africa to anyone looking for reliable, top-tier service.',NULL,NULL,'admin',0,'approved',0,'2025-11-08 06:21:23','2025-11-08 06:21:32'),(9,'8b214f5bc07ff124','Sir James','james@gmail.com','Accountant','East African Canvas','/storage/profile/testimonials/review1-1762583756455.png',5,'Thanks to BEKE Africa, I am now a proud owner of an exquisite apartment in a great neighborhood. I\'d recommend them to anyone looking for a reliable ,trustworthy and client-focused real estate company.',NULL,NULL,'admin',0,'approved',0,'2025-11-08 06:35:56','2025-11-08 06:36:00'),(10,'af2802ab84616aa8','Joe Kinyanjui','joe@gmail.com','Entrepreneur','MQ 3D Solutions','/storage/profile/testimonials/testimonial-1762585028279.jpg',5,'I am now happily settled in my new villa and i couldn\'t be more grateful for the outstanding service from BEKE Africa. I highly recommend them to anyone looking for a reliable and trustworthy real estate partner.',NULL,NULL,'admin',0,'approved',0,'2025-11-08 06:57:08','2025-11-08 06:57:17'),(12,'8753186ca4d37cb2','MR. Patrick ','patrick@gmail.com','Magistrate','Judicial Service Commission','/storage/profile/testimonials/land-1762765270783.jpg',5,'Their market knowledge, responsiveness and negotiation skills ensured my family got the right parcel of land at the right price and location. Highly recommend BEKE Africa',NULL,13,'admin',0,'approved',0,'2025-11-10 09:01:10','2025-11-10 09:01:22'),(13,'ece5b6c5be5dc04b','Tadiwa Collins','tadiwa@gmail.com','Facilitator','International School of  Kenya','/storage/profile/testimonials/garden-1762766506979.jpg',5,'BEKE Africa made it possible for us to give our parents the home they have always dreamed of. Their team was professional, transparent and incredibly supportive  throughout the entire process. They guided us from property selection to final paperwork, making everything smooth and well coordinated. We\'re truly grateful to BEKE Africa for helping us make this special gift a reality. ',NULL,13,'admin',0,'approved',0,'2025-11-10 09:21:46','2025-11-10 09:21:55'),(14,'19cacc4cd01b01b0','Andrew Alani','andrew@gmal.com','Concierge','Serena Hotel','/storage/profile/testimonials/ocean-house-1762768166665.jpg',5,'My property investment journey was seamless and straightforward. Their expertise and guidance ensured i secured a high- quality property with confidence. I highly recommend BEKE to anyone looking to invest in Real estate.',NULL,13,'admin',0,'approved',0,'2025-11-10 09:49:26','2025-11-10 09:49:52'),(15,'cbe6f2f02ef0733a','Miss Aria','aria@gmail.com','Nutritionist','NutriAxis Nutrition Consultancy Ltd','/storage/profile/testimonials/cartier-1-1763122051051.jpg',5,'Working with BEKE Real estate has been an exceptional experience. From the very first viewing , the team made me feel supported, informed and confident in every step of the process. Thanks to their professionalism and dedication , I am now the proud owner of the stunning Cartier villa.\r\n\r\nA special thanks -to you to the entire BEKE Real Estate team for their transparency, patience and commitment to finding me the perfect home. I couldn\'t be happier with my decision.',NULL,13,'admin',0,'approved',0,'2025-11-14 12:07:31','2025-11-14 12:09:29'),(16,'3188d24b3a65950e','Sheryl ','margaret@gmail.com','Data Analyst','Nakala','/storage/profile/testimonials/sold-1767682443303.png',5,'\"Buying a 3- bedroom house in Nairobi felt overwhelming at first, but working with Beke Information Technology made the entire process smooth and stress -free. From the initial consultation to the final paper work, their team was professional , transparent and very responsive. They took time to understand my needs, shared  genuine property options and guided me step by step until I found the perfect home. I especially appreciated their honesty and attention to detail. Thanks to Beke Information Technology, I am now a proud homeowner in Nairobi. I highly recommend them to anyone looking to buy property with confidence.\"',NULL,13,'admin',0,'approved',0,'2026-01-06 06:54:03','2026-01-06 06:55:33');
