INSERT INTO `translations` VALUES (1,'hero_slide',1,'zh','title','您值得信赖的房地产合作伙伴'),(2,'hero_slide',1,'zh','subtitle','在肯尼亚房地产开发领域拥有超过5年的卓越经验'),(3,'hero_slide',1,'zh','button_text','浏览房源'),(16,'apartment_layout',1,'zh','name','单间'),(17,'apartment_layout',1,'zh','description','带浴室和小厨房的单间'),(18,'apartment_layout',2,'zh','name','一居室'),(19,'apartment_layout',2,'zh','description','一卧室公寓'),(20,'apartment_layout',3,'zh','name','两居室'),(21,'apartment_layout',3,'zh','description','两卧室公寓'),(22,'apartment_layout',4,'zh','name','三居室'),(23,'apartment_layout',4,'zh','description','三卧室公寓'),(24,'property_category',1,'zh','name','出售'),(25,'property_category',1,'zh','description','可供购买的房产'),(26,'property_category',2,'zh','name','出租'),(27,'property_category',2,'zh','description','可供出租或租赁的房产'),(28,'property_category',3,'zh','name','商业'),(29,'property_category',3,'zh','description','办公楼、商店和商业空间'),(30,'property_type',1,'zh','name','公寓'),(31,'property_type',1,'zh','description','住宅公寓和套房'),(32,'property_type',2,'zh','name','别墅'),(33,'property_type',2,'zh','description','独栋别墅和豪华住宅'),(34,'property_type',3,'zh','name','土地'),(35,'property_type',3,'zh','description','空地和可开发用地'),(48,'blog_category',1,'zh','name','房地产趋势'),(49,'blog_category',1,'zh','description','深入了解最新房地产市场趋势、房价和开发动态。'),(50,'blog_category',2,'zh','name','购房指南'),(51,'blog_category',2,'zh','description','为首次购房者和有经验的买家提供实用建议。'),(52,'blog_category',3,'zh','name','室内设计'),(53,'blog_category',3,'zh','description','为您的家提供装饰与布置灵感。'),(56,'blog_post',1,'zh','title','肯尼亚2025年房地产市场展望'),(57,'blog_post',1,'zh','excerpt','深入分析肯尼亚住房市场表现、价格趋势和投资机会。'),(58,'blog_post',1,'zh','content','<p>尽管经济环境波动，肯尼亚房地产市场依然保持韧性。开发商专注于可负担住房，而高端项目在内罗毕和蒙巴萨持续增长。</p>'),(59,'blog_post',2,'zh','title','首次购房者必须知道的10个提示'),(60,'blog_post',2,'zh','excerpt','准备购买第一套房？以下十条建议帮助您避免常见错误。'),(61,'blog_post',2,'zh','content','<p>购买第一套房可能让人不知所措。从获得贷款预批准到选择合适的社区，这些提示将帮助您做出明智的决定。</p>'),(62,'blog_post',3,'zh','title','正在改变内罗毕家庭的5大室内设计趋势'),(63,'blog_post',3,'zh','excerpt','现代美学、环保设计和智能家居创新正在重新定义内罗毕的居住空间。'),(64,'blog_post',3,'zh','content','<p>从极简家具到可持续材料，内罗毕的房主们正在接受现代室内设计理念。了解如何让您的家更时尚实用。</p>'),(65,'blog_post',4,'zh','title','为什么房地产在2025年仍是明智的投资'),(66,'blog_post',4,'zh','excerpt','尽管全球市场波动，房地产仍是稳定且有利可图的投资。'),(67,'blog_post',4,'zh','content','<p>在经济不确定的时期，房地产依然是最可靠的投资之一。学习如何发现有利可图的机会并降低风险。</p>'),(68,'blog_post',1,'zh','tags','[\"肯尼亚\", \"房地产\", \"房产市场\", \"趋势\", \"投资\"]'),(69,'blog_post',2,'zh','tags','[\"购房者\", \"房地产技巧\", \"按揭贷款\", \"购房指南\", \"首次购房\"]'),(70,'blog_post',3,'zh','tags','[\"室内设计\", \"内罗毕住宅\", \"家居装饰\", \"生活方式\", \"趋势\"]'),(71,'blog_post',4,'zh','tags','[\"投资\", \"房地产\", \"智能投资\", \"房产\", \"金融\"]'),(124,'property_decorations',1,'zh','name','空屋——'),(125,'property_decorations',2,'zh','name','半家具'),(126,'property_decorations',3,'zh','name','设施齐全'),(127,'property_decorations',4,'zh','name','整建'),(128,'property_decorations',5,'zh','name','需要翻新'),(129,'property_conditions',1,'zh','name','New'),(130,'property_conditions',2,'zh','name','优秀'),(131,'property_conditions',3,'zh','name','较高'),(132,'property_conditions',4,'zh','name','般'),(133,'property_conditions',5,'zh','name','舊'),(134,'property_conditions',6,'zh','name','需要维修'),(135,'property_orientations',1,'zh','name','北部'),(136,'property_orientations',2,'zh','name','南部'),(137,'property_orientations',3,'zh','name','东部'),(138,'property_orientations',4,'zh','name','西部'),(1886,'property',1,'zh','property_name','PINECREST公寓'),(1887,'property',1,'zh','detailed_address','Kindaruma路'),(1888,'property',1,'zh','description','<p><strong><u>PINCREST RESIDENCE UNITS FOR RENT</u></strong></p><p><br></p><p>Situated in a serene and secure environment, this unit offers:</p><p>Space&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p><p>Security</p><p>Privacy </p><p>Excellent road access</p><p>Location- Kilimani along Kindaruma road</p><p><br></p><p><strong>Features and amenities</strong></p><p><br></p><p>● Heated swimming pool</p><p>● Steam sauna</p><p>● Fully fitted gym</p><p>● Fully fitted kitchen </p><p>● Full backup generator </p><p>● Ample parking </p><p>● High speed lifts </p><p>● Smart lock door</p><p>● Borehole </p><p><br></p><p>Pincrest residence is in close proximity to these important facilities;</p><p><br></p><p>Top schools</p><p>Hospitals</p><p>Shopping malls and restaurants</p><p>Excellent road access</p><p><br></p><p><strong>Unit sizes and prices</strong></p><p>1 bedrooms - all sold out</p><p>2 bedrooms - 112 sqm</p><p><br></p>'),(1889,'property',2,'zh','property_name','阁楼'),(1890,'property',2,'zh','description','<h2><u>The Lofts At Wood Avenue - Kilimani Apartment</u></h2><p><span style=\"color: rgb(40, 44, 52);\">Located about 10 minutes by car from Uhuru Park, The Lofts At Wood Avenue - Kilimani Apartment Nairobi gives access to a number of tourist attractions in the area.</span></p><p><strong>The Lofts At Wood Avenue - Kilimani Apartment</strong> comprises a balcony and a seating area featuring a sofa set, and modern comforts like a multi-channel television. Bathrooms come with a separate toilet and a shower. Additionally, you\'ll find dryers and towels.</p><p>There are a refrigerator, an oven, and kitchenware provided for guests at the apartment. This accommodation is only a stone\'s throw from the pub Jiweke Tavern.</p><p>This apartment lies at a moderate distance from Shifteye Gallery. David Sheldrick Wildlife Trust is within a 10-minute drive of the property. The nearest airport is Wilson, 10 km from this apartment, and Prestige Plaza bus station is only 350 metres away.</p><h3><u>Features and amenities</u></h3><h3>General</h3><ul><li>Wi-Fi</li><li>Safe deposit box</li></ul><h4>Dining</h4><ul><li>Dryer</li><li>Cookware/ Kitchen utensils</li><li>Outdoor dining area</li></ul><h4>Room Amenities</h4><ul><li>Sitting area</li><li>Dining table</li><li>Washing machine</li><li>Flat-screen TV</li><li>Alarm clock</li><li>Carpeted floor</li></ul><p><strong>Unit size and price:</strong></p><p>2 Bedrooms 55sqm at Ksh 285,000</p><p><br></p>'),(1891,'property',3,'zh','property_name','SUNSTONE GENERAL MATHENGE'),(1892,'property',3,'zh','detailed_address','General Mathenge Westlands'),(1893,'property',3,'zh','description','<p><br></p><p>Discover comfort and convenience in these beautifully maintained house units located in General Mathenge.</p><p><br></p><p><strong>Key Amenities included with the unit:</strong></p><p><br></p><ul><li>Spacious main kitchen and a separate preparation kitchen</li><li>Dedicated laundry area</li><li>Large lounge and dining spaces</li><li>Smart home finishes</li><li>2 high-speed elevators</li><li>Heated swimming pool and kids’ play area</li><li>Café, yoga studio, control room</li><li>CCTV surveillance, borehole water, backup generator</li><li>Mini shop on-site</li><li>High-quality modern finishes and ample parking, including visitor slots</li></ul><p><br></p><p><strong>The summary below outlines available apartments categorized by type, floor, parking spaces, size, and rental amount:</strong></p><p><br></p><ol><li>2-Bedroom + DSQ Apartments Located on Floors 4, 7 to 12. Each unit has 1 parking space. Size: 1,700 sqft (158 sqm). Monthly rent ranges from 145,000 to 155,000.</li><li>4-Bedroom + DSQ Apartments Located on Floors 13 to 15. Each unit has 3 parking spaces. Size: 3,400 sqft (316 sqm). Monthly rent ranges from 325,000 to 350,000.</li><li>5-Bedroom + DSQ Apartments Located on Floors 13 and 14. Each unit has 3 parking spaces. Size: 4,800 sqft (446 sqm). Monthly rent: 425,000.</li></ol><p><br></p><p>This home is just moments away from the following key facilities:</p><p><br></p><ul><li>Excellent road access</li><li>Hospitals</li><li>Top schools</li><li>Shopping malls and dinning areas</li></ul>'),(1896,'property',5,'zh','property_name','KENZI公寓'),(1897,'property',5,'zh','description','<p><br></p><p>Welcome to Kenzi residence offering a perfect blend of privacy, space, and easy access to essential amenities.</p><p><br></p><p><strong>Apartment features and amenities:</strong></p><p><br></p><ul><li>Clever, contemporary layouts with high-end finishes:</li><li>Floor-to-ceiling sliding windows</li><li>Granite countertops, high-pressure rain showers</li><li>Built-in wardrobes, MDF kitchen cabinets, gypsum bulkheads</li><li>Unit amenities include private balconies (in some units), in‑unit laundry setups, and modern intercom systems .</li></ul><p><br></p><p><strong>Building Amenities</strong></p><p><br></p><p>Residents enjoy upscale facilities such as:</p><p>Heated resort-style swimming pool</p><p>Full gym, steam room &amp; sauna, Yoga/Juice bar</p><p>Rooftop garden lounge and social house (movie/meeting room, billiards)</p><p>24‑hour CCTV, access control, borehole water supply, backup generator</p><p>High-speed lifts and landscaped garden areas .</p><p><br></p><p>Unit sizes and price:</p><p><br></p><ul><li>Studio sqm (34–35) 80K – 120K (unfurnished est.)</li><li>Deluxe Studio sqm( 49) 150k</li><li>1-Bedroom sqm( 53–61)&nbsp;120K – 150K+ (furnished est.)</li></ul>'),(1898,'property',6,'zh','property_name','LE MAC'),(1899,'property',6,'zh','description','<p><strong><u>1 Bedroom for rent in Westlands</u></strong></p><p>Le’Mac is a statement of impeccable architecture with immense attention to detail and a fine blend of spaces to allow functional flows with ensuring utmost privacy.</p><p><strong>Apartment&nbsp;features:</strong></p><ul><li>Avant grade finishes</li><li>Floor to ceiling windows</li><li>Spacious kitchen</li><li>Spacious dinning area</li><li>Balcony with ample space</li><li>Spectacular views</li></ul><p><strong>Prime location</strong></p><p>Le mac is moments away from key facilities:</p><p>Top schools</p><p>Hospitals</p><p>Excellent road access</p><p>Shopping malls and restaurants</p><p><strong>Unit sizes and price</strong></p><p>127 SQM at Ksh 150,000 per month</p><p><br></p>'),(1900,'property',7,'zh','property_name','VOLAIRE'),(1901,'property',7,'zh','description','<p><br></p><p>Discover this beautifully maintained 2 bedroom located in Westlands .</p><p>This unit offers a perfect blend of privacy ,space , security and access to essential amenities.</p><p>Each apartment features:</p><p>terrace</p><p>balcony</p><p>washing machine</p><p>fully equipped kitchen</p><p>TV</p><p><strong>Essential Facilities:</strong></p><p>Guests enjoy free WiFi, free on-site private parking, and a private pool. The property provides a relaxing environment with a terrace and balcony.</p><p><br></p><p><strong>Convenient Location:</strong> Located 5.6 mi from Wilson Airport, the apartment is close to attractions such as Nairobi National Museum (2.5 mi), Kenyatta International Conference Center (3.1 mi), and Nairobi Botanic Garden (2.5 mi).</p><p><br></p><p><strong>Local Surroundings:</strong> A restaurant is available in the surrounding area, offering diverse dining options.</p><p><strong>Unit size and price :</strong></p><p>2 Bedroom 84sqm at Ksh 250,000</p><p><br></p>'),(1902,'property',8,'zh','property_name','LE MAC'),(1903,'property',8,'zh','description','<p><strong><u>2 Bedroom for rent in Westlands</u></strong></p><p>Le’Mac is a statement of impeccable architecture with immense attention to detail and a fine blend of spaces to allow functional flows with ensuring utmost privacy.</p><p><br></p><p>Apartment&nbsp;features:</p><p><br></p><ul><li>Avant grade finishes</li><li>Floor to ceiling windows</li><li>Spacious kitchen</li><li>Spacious dinning area</li><li>Balcony with ample space</li><li>Spectacular views</li></ul><p><strong>Prime location:</strong></p><p>Le mac is moments away from key facilities:</p><p>Top schools</p><p>Hospitals</p><p>Excellent road access</p><p>Shopping malls and restaurants</p><p>Unit sizes and price:</p><ul><li>142 sqm at Ksh 250,000 per month</li></ul><p><br></p><p><br></p>'),(1906,'property',10,'zh','property_name','KRESTONE公寓'),(1907,'property',10,'zh','description','<p><strong><u>1 BEDROOM FOR RENT</u></strong></p><p><br></p><p>Located in Westland\'s along School Lane, this modern newly built apartment block is conveniently located within walking distance to shopping centers, offices and entertainment spots.</p><p>Newly built 1bedroom units with master ensuite and good lighting. Open floor plan with a seamless flow between the dining and living area. Quality finishes throughout the building with large windows and a balcony for every unit.</p><p>Located in the upscale Westlands area close to key shopping centres including Sarit Centre, Westgate Mall, commercial offices, restaurants and entertainment hot spots.</p><p><br></p><p><strong>Amenities:</strong></p><p>Full backup generator</p><p>High speed lifts</p><p>Ample Parking space</p><p>Electric fence</p><p>Fully equipped gym</p><p>Good security with CCTV surveillance and Electric fence.</p><p>Manned gate</p><p><strong>Unit&nbsp;size and price:</strong></p><p>1 bedroom&nbsp;45 sqm - Ksh 75,000 Inclusive of service charge</p>'),(1908,'property',11,'zh','property_name','KRESTONE公寓'),(1909,'property',11,'zh','description','<p><strong><u>2 BEDROOMS FOR RENT</u></strong></p><p>Located in Westlands along School Lane, this modern newly built apartment block is conveniently located within walking distance to shopping centres, offices and entertainment spots.</p><p>Newly built&nbsp;2-bedroom units with master ensuite and good lighting. Open floor plan with a seamless flow between the dining and living area. Quality finishes throughout the building with large windows and a balcony for every unit.</p><p>Located in the upscale Westlands area close to key shopping centers including Sarit Centre, Westgate Mall, commercial offices, restaurants and entertainment hot spots.</p><p><strong>Amenities:</strong></p><ul><li>Full backup generator</li><li>High speed lifts</li><li>Ample Parking space</li><li>Electric fence</li><li>Fully equipped gym</li><li>Good security with CCTV surveillance and Electric fence.</li><li>Manned gate</li></ul><p><strong>Unit size and price:</strong></p><p>2 bedroom 85sqm&nbsp;– Ksh 95,000 Inclusive of service charge</p>'),(1914,'property',14,'zh','property_name','BAHARI房源'),(1915,'property',14,'zh','description','<p><strong><u>UNITS FOR RENT </u></strong></p><p>Welcome to Bahari homes situated in a serene and secure environment offering a perfect blend of space, security, privacy and easy access to essential amenities.</p><p><br></p><p><br></p><p>AMENITIES;&nbsp;</p><p><br></p><ul><li>High speed Lifts&nbsp;</li><li>Heated pool</li><li>Kids cycling area</li><li>Event center</li><li>Manned security</li><li>Intercom</li><li>Fitted kitchen</li><li>Extended balconies</li><li>Large window</li></ul><p><br></p><p>2-Bedroom</p><p><br></p><p>KES 150,000/month</p><p>KES 200,000/month -Furnished</p><p><br></p><p><br></p><p><br></p>'),(1922,'property',18,'zh','property_name','CULLINAN公寓'),(1923,'property',18,'zh','description','<p><strong><u>Units for rent </u></strong></p><p>Welcome to these units along Nyangumi road off Dennis Pritt road.</p><p><br></p><p><strong>Features and amenities:</strong></p><p><br></p><p>✅ Readily accessible social amenities including The Nairobi Hospital and Coptic Hospital just a few minutes away and Shopping malls for any and all your necessities.</p><p>✅ Adequate supply of Water and Electricity.</p><p>✅ 24/7 Security Services.</p><p>Situated in a serene and secure environment , this home is just minutes away from key facilities:</p><ul><li>Top schools</li><li>Hospitals</li><li>Shopping malls and dinning</li><li>Excellent road access</li></ul><p><strong>Unit price:</strong></p><ul><li>1 bedroom furnished&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Ksh 100,000</li><li>2 bedroom master en-suite. furnished&nbsp;&nbsp;&nbsp;&nbsp;Ksh 120,000</li><li>3 bedroom furnished&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Ksh 120,000</li></ul>'),(1924,'property',19,'zh','property_name','NANDWA常春藤'),(1925,'property',19,'zh','description','<p><stro