INSERT INTO `user_products` VALUES (13,13,'Modern Wall Panels (3D PVC)','Interior Decor',2,'3d_panel.jpg','[\"3d_panel.jpg\", \"3d_panel_white.jpg\"]',2024,'3D wall panels for interior decoration.','Lightweight PVC wall panels suitable for living rooms, offices and interior enhancement. Comes in multiple textures and colors.','2025-11-18 21:19:36'),(14,13,'Luxury Vinyl Flooring','Flooring',3,'vinyl_floor.jpg','[\"vinyl_floor.jpg\", \"vinyl_floor_dark.jpg\"]',2024,'Durable and waterproof vinyl flooring.','High-density vinyl planks with wood texture. Resistant to scratches and moisture—perfect for residential and commercial spaces.','2025-11-18 21:19:36'),(15,14,'Reinforcement Steel Bars (D8–D32)','Construction Materials',1,'steel_bars.jpg','[\"steel_bars.jpg\"]',2024,'High-grade reinforcement steel bars for construction.','TradeMax supplies ribbed reinforcement steel bars ranging from D8 to D32, compliant with KEBS standards for structural strength.','2025-11-18 21:19:36'),(16,14,'Chain Link Fencing 10M','Fencing',4,'chainlink.jpg','[\"chainlink.jpg\"]',2024,'10-meter chain link fencing roll.','Galvanized chain link fencing ideal for farms, schools, residential properties, and boundary protection.','2025-11-18 21:19:36'),(17,15,'Ceramic Tiles 60x60cm','Flooring',3,'tiles60.jpg','[\"tiles60.jpg\", \"tiles60_gloss.jpg\"]',2024,'Premium ceramic tiles for floor finishing.','High-gloss ceramic tiles with modern patterns. Suitable for living rooms, hallways, and commercial spaces.','2025-11-18 21:19:36'),(18,15,'Paint — Acrylic Emulsion (20L)','Paints',5,'acrylic_paint.jpg','[\"acrylic_paint.jpg\"]',2024,'High-quality acrylic wall paint.','Low-odor formula with long-lasting color retention. Great for both indoor and outdoor walls.','2025-11-18 21:19:36'),(19,16,'PVC Gutters Set (10ft)','Roofing Accessories',6,'pvc_gutter.jpg','[\"pvc_gutter.jpg\"]',2023,'Complete PVC gutter set for roofing.','UV-resistant and leak-proof PVC gutter system ideal for residential roofs. Comes with connectors and end caps.','2025-11-18 21:19:36'),(20,16,'Portable Water Tank 1000L','Water Storage',7,'water_tank.jpg','[\"water_tank.jpg\"]',2024,'High-quality 1000-liter plastic water tank.','Made from food-grade plastic with UV protection. Suitable for home, commercial, and construction site use.','2025-11-18 21:19:36');
